 35→export function parseCommand(input: string): Command {
 36→  if (!input.startsWith("/")) return { type: "chat", message: input };
 37→
 38→  const spaceIdx = input.indexOf(" ");
 39→  const cmd = spaceIdx === -1 ? input : input.slice(0, spaceIdx);
 40→  const rest = spaceIdx === -1 ? "" : input.slice(spaceIdx + 1);
 41→
 42→  switch (cmd) {
 43→    case "/s":
 44→    case "/say":
 45→      return { type: "say", message: rest };
 46→    case "/y":
 47→    case "/yell":
 48→      return { type: "yell", message: rest };
 49→    case "/g":
 50→    case "/guild":
 51→      return { type: "guild", message: rest };
 52→    case "/p":
 53→    case "/party":
 54→      return { type: "party", message: rest };
 55→    case "/raid":
 56→      return { type: "raid", message: rest };
 57→    case "/w":
 58→    case "/whisper": {
 59→      const targetEnd = rest.indexOf(" ");
 60→      if (targetEnd === -1)
 61→        return { type: "whisper", target: rest, message: "" };
 62→      return {
 63→        type: "whisper",
 64→        target: rest.slice(0, targetEnd),
 65→        message: rest.slice(targetEnd + 1),
 66→      };
 67→    }
 68→    case "/r":
