  conn: WorldConn,
  r: PacketReader,
): void {
  const packet = parseGuildCommandResult(r);
  const msg = formatGuildCommandError(
    packet.command,
    packet.name,
    packet.result,
  );
  if (msg) {
    conn.onGuildEvent?.({
