2600→+export function formatGuildCommandError(
2601→+  _command: number,
2602→+  name: string,
2603→+  result: number,
2604→+): string | undefined {
2605→+  switch (result) {
2606→+    case GuildCommandResult.PLAYER_NO_MORE_IN_GUILD:
2607→+      return undefined;
2608→+    case GuildCommandResult.GUILD_INTERNAL:
2609→+      return "[guild] Internal guild error";
2610→+    case GuildCommandResult.ALREADY_IN_GUILD:
2611→+      return "[guild] You are already in a guild";
2612→+    case GuildCommandResult.ALREADY_IN_GUILD_S:
2613→+      return `[guild] ${name} is already in a guild`;
2614→+    case GuildCommandResult.INVITED_TO_GUILD:
2615→+      return "[guild] You have already been invited to a guild";
2616→+    case GuildCommandResult.ALREADY_INVITED_TO_GUILD_S:
2617→+      return `[guild] ${name} has already been invited to a guild`;
2618→+    case GuildCommandResult.GUILD_NAME_INVALID:
2619→+      return "[guild] Invalid guild name";
2620→+    case GuildCommandResult.GUILD_NAME_EXISTS_S:
2621→+      return `[guild] Guild name "${name}" already exists`;
2622→+    case GuildCommandResult.GUILD_LEADER_LEAVE_OR_PERMISSIONS:
2623→+      return "[guild] You don't have permission to do that";
2624→+    case GuildCommandResult.GUILD_PLAYER_NOT_IN_GUILD:
2625→+      return "[guild] You are not in a guild";
2626→+    case GuildCommandResult.GUILD_PLAYER_NOT_IN_GUILD_S:
2627→+      return `[guild] ${name} is not in your guild`;
2628→+    case GuildCommandResult.GUILD_PLAYER_NOT_FOUND_S:
2629→+      return `[guild] Player "${name}" not found`;
2630→+    case GuildCommandResult.GUILD_NOT_ALLIED:
2631→+      return `[guild] ${name} is not the same alliance as you`;
2632→+    case GuildCommandResult.GUILD_RANK_TOO_HIGH_S:
2633→+      return `[guild] ${name} has a rank too high for that`;
2634→+    case GuildCommandResult.GUILD_RANK_TOO_LOW_S:
2635→+      return `[guild] ${name} has a rank too low for that`;
2636→+    case GuildCommandResult.GUILD_RANKS_LOCKED:
2637→+      return "[guild] Guild ranks are locked";
2638→+    case GuildCommandResult.GUILD_RANK_IN_USE:
2639→+      return "[guild] That guild rank is in use";
2640→+    case GuildCommandResult.GUILD_IGNORING_YOU_S:
2641→+      return `[guild] ${name} is ignoring you`;
2642→+    default:
2643→+      return `[guild] Guild command error (${result})`;
2644→+  }
2645→+}
