    );
    conn.dispatch.on(GameOpcode.SMSG_DUEL_COUNTDOWN, (r) =>
      handleDuelCountdown(conn, r),
    );
    conn.dispatch.on(GameOpcode.SMSG_DUEL_COMPLETE, (r) =>
