      handleDuelOutOfBounds(conn),
    );
    conn.dispatch.on(GameOpcode.SMSG_DUEL_INBOUNDS, () =>
      handleDuelInBounds(conn),
    );
    conn.dispatch.on(GameOpcode.SMSG_PARTY_COMMAND_RESULT, (r) =>
      handlePartyCommandResult(conn, r),
