    w.cString("Sylvanas");
    w.uint64LE(7n);
    const r = new PacketReader(w.finish());
    parseGuildEvent(r);
    expect(r.remaining).toBe(0);
  });

  test("parses SIGNED_OFF with trailing guid", () => {
    const w = new PacketWriter();
    w.uint8(GuildEventCode.SIGNED_OFF);
    w.uint8(1);
    w.cString("Varian");
    w.uint64LE(55n);
    const r = new PacketReader(w.finish());
    parseGuildEvent(r);
    expect(r.remaining).toBe(0);
  });

  test("parses REMOVED with 2 string params", () => {
