        w.uint8(1);
        w.cString("Thrall");
        w.uint64LE(10n);
        ws.inject(GameOpcode.SMSG_GUILD_EVENT, w.finish());

        const event = await eventReady;
        expect(event.type).toBe("signed_on");
        if (event.type === "signed_on") {
