      const promise = dispatchCommand(
        { type: "read_wait", ms: 1000 },
        handle,
        events,
        socket,
        cleanup,
      );

      events.push({ text: "[say] New: during", json: '{"type":"SAY"}' });
      jest.advanceTimersByTime(1000);
